import{_ as r,o,c as a,ai as n,aj as t}from"./chunks/framework.DG6aArJf.js";const g=JSON.parse('{"title":"Sponsor DOM Helpers","description":"","frontmatter":{},"headers":[],"relativePath":"sponsor/sponsor.md","filePath":"sponsor/sponsor.md"}'),s={name:"sponsor/sponsor.md"};function i(l,e,p,u,h,d){return o(),a("div",null,[...e[0]||(e[0]=[n('<p><a href="https://github.com/sponsors/giovanni1707" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/Sponsor-%F0%9F%92%96-pink" alt="Sponsor"></a></p><p><a href="https://paypal.me/GiovanniSylvain" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/Sponsor-PayPal-blue?logo=paypal" alt="Sponsor"></a></p><h1 id="sponsor-dom-helpers" tabindex="-1">Sponsor DOM Helpers <a class="header-anchor" href="#sponsor-dom-helpers" aria-label="Permalink to “Sponsor DOM Helpers”">​</a></h1><div class="creator"><img src="'+t+'" alt="Giovanni Marianne" class="creator-photo"><div class="creator-info"><p><strong>Giovanni Marianne</strong></p><p>Creator of DOM Helpers Library</p></div></div><p>DOM Helpers is a free, open-source library that provides reactivity and simplifies DOM manipulation for developers worldwide. Your sponsorship, no matter the amount, helps ensure continued development, maintenance, and support for the community.</p><h2 id="why-sponsor" tabindex="-1">Why Sponsor? <a class="header-anchor" href="#why-sponsor" aria-label="Permalink to “Why Sponsor?”">​</a></h2><p>DOM Helpers is built and maintained with care to provide:</p><ul><li><strong>Zero dependencies</strong> — lightweight and performant</li><li><strong>Developer-friendly API</strong> — intuitive methods for common DOM tasks</li><li><strong>Active maintenance</strong> — regular updates, bug fixes, and improvements</li><li><strong>Community support</strong> — responsive help and feature requests</li><li><strong>Comprehensive documentation</strong> — clear guides and examples</li></ul><p>Your sponsorship, whether large or small, directly supports:</p><p>✅ <strong>Active Development</strong> — new features and improvements<br> ✅ <strong>Bug Fixes &amp; Security</strong> — timely patches and updates<br> ✅ <strong>Documentation</strong> — keeping guides current and comprehensive<br> ✅ <strong>Community Support</strong> — responding to issues and questions<br> ✅ <strong>Long-term Sustainability</strong> — ensuring the library remains maintained</p><h2 id="every-contribution-matters" tabindex="-1">Every Contribution Matters <a class="header-anchor" href="#every-contribution-matters" aria-label="Permalink to “Every Contribution Matters”">​</a></h2><p>All contributions are valued and appreciated equally. Whether you can contribute once or regularly, every bit of support helps keep this project alive and thriving.</p><p><strong>Your support enables:</strong></p><ul><li>Dedicated time for development and maintenance</li><li>Infrastructure costs (hosting, domains, CI/CD)</li><li>Tools and resources for better development</li><li>Community initiatives and improved documentation</li><li>Video tutorials</li></ul><h2 id="how-to-sponsor" tabindex="-1">How to Sponsor <a class="header-anchor" href="#how-to-sponsor" aria-label="Permalink to “How to Sponsor”">​</a></h2><p>Choose the platform that works best for you:</p><h3 id="github-sponsors-recommended" tabindex="-1">GitHub Sponsors (Recommended) <a class="header-anchor" href="#github-sponsors-recommended" aria-label="Permalink to “GitHub Sponsors (Recommended)”">​</a></h3><p><a href="https://github.com/sponsors/giovanni1707" target="_blank" rel="noreferrer">Sponsor @giovannimarianne on GitHub</a></p><h3 id="other-payment-methods" tabindex="-1">Other Payment Methods <a class="header-anchor" href="#other-payment-methods" aria-label="Permalink to “Other Payment Methods”">​</a></h3><ul><li><strong>PayPal:</strong> <a href="https://paypal.me/GiovanniSylvain" target="_blank" rel="noreferrer">paypal.me</a></li></ul><p><strong>All amounts are welcome</strong> — contribute what feels right for you, whether it&#39;s a one-time gift or ongoing support.</p><h2 id="corporate-business-use" tabindex="-1">Corporate &amp; Business Use <a class="header-anchor" href="#corporate-business-use" aria-label="Permalink to “Corporate &amp; Business Use”">​</a></h2><p>If your company or organization uses DOM Helpers in production, I&#39;d love to hear about it! Understanding how the library is being used in real-world applications helps guide its development and ensures it continues to meet professional needs.</p><p><strong>I&#39;m open to discussing:</strong></p><ul><li>How DOM Helpers fits into your workflow</li><li>Features that would make it more valuable for your team</li><li>Ways we can collaborate to make the library better</li><li>Support arrangements as the project grows</li></ul><p><strong>Contact:</strong> <a href="mailto:giovannimarianne1@gmail.com" target="_blank" rel="noreferrer">giovannimarianne1@gmail.com</a></p><h2 id="recognition-gratitude" tabindex="-1">Recognition &amp; Gratitude <a class="header-anchor" href="#recognition-gratitude" aria-label="Permalink to “Recognition &amp; Gratitude”">​</a></h2><p>All sponsors who wish to be recognized will be:</p><ul><li>Listed in the project README (unless you prefer to remain anonymous)</li><li>Mentioned in release notes</li><li>Given a heartfelt thank you from the maintainer</li></ul><p><strong>Your contribution, regardless of size, makes a real difference.</strong></p><h2 id="current-sponsors" tabindex="-1">Current Sponsors <a class="header-anchor" href="#current-sponsors" aria-label="Permalink to “Current Sponsors”">​</a></h2><h3 id="🌟-amazing-people-organizations-supporting-dom-helpers" tabindex="-1">🌟 Amazing People &amp; Organizations Supporting DOM Helpers <a class="header-anchor" href="#🌟-amazing-people-organizations-supporting-dom-helpers" aria-label="Permalink to “🌟 Amazing People &amp; Organizations Supporting DOM Helpers”">​</a></h3><p><em>Become the first sponsor and help build something great!</em></p><h2 id="transparency" tabindex="-1">Transparency <a class="header-anchor" href="#transparency" aria-label="Permalink to “Transparency”">​</a></h2><p>I believe in being open about how sponsorship funds are used:</p><ul><li><strong>Development Time</strong> — dedicated hours for coding, testing, and maintenance</li><li><strong>Infrastructure</strong> — hosting, domains, CI/CD services</li><li><strong>Tools &amp; Resources</strong> — development tools and learning resources</li><li><strong>Community</strong> — documentation, support, and outreach</li></ul><p>Regular updates on project progress and fund usage will be shared with the community.</p><h2 id="frequently-asked-questions" tabindex="-1">Frequently Asked Questions <a class="header-anchor" href="#frequently-asked-questions" aria-label="Permalink to “Frequently Asked Questions”">​</a></h2><p><strong>Q: Is there a minimum amount?</strong><br> A: No! All contributions are gratefully accepted, no matter how small.</p><p><strong>Q: Can I sponsor anonymously?</strong><br> A: Absolutely. Just let me know your preference.</p><p><strong>Q: What if I want to discuss a custom arrangement?</strong><br> A: Please reach out at <a href="mailto:giovannimarianne1@gmail.com" target="_blank" rel="noreferrer">giovannimarianne1@gmail.com</a> — I&#39;m happy to chat!</p><h2 id="alternative-ways-to-support" tabindex="-1">Alternative Ways to Support <a class="header-anchor" href="#alternative-ways-to-support" aria-label="Permalink to “Alternative Ways to Support”">​</a></h2><p>Not able to sponsor financially right now? You can still make a huge impact:</p><ul><li>⭐ <strong>Star the repository</strong> on GitHub</li><li>🐛 <strong>Report bugs</strong> and suggest features</li><li>📝 <strong>Improve documentation</strong> with pull requests</li><li>💬 <strong>Share DOM Helpers</strong> with other developers</li><li>✍️ <strong>Write tutorials</strong> or blog posts about the library</li><li>🔧 <strong>Contribute code</strong> to help build new features</li><li>🗣️ <strong>Spread the word</strong> on social media</li></ul><h2 id="thank-you" tabindex="-1">Thank You <a class="header-anchor" href="#thank-you" aria-label="Permalink to “Thank You”">​</a></h2><p>Every contribution, whether it&#39;s code, feedback, or financial support, helps keep DOM Helpers growing and improving. Your generosity makes open-source software sustainable.</p><p><strong>With sincere gratitude,</strong><br> Giovanni Marianne<br> Creator &amp; Maintainer of DOM Helpers</p><p><em>DOM Helpers is MIT licensed and will always remain free and open source.</em><br><em>Sponsorship helps ensure it stays that way.</em></p>',48)])])}const c=r(s,[["render",i]]);export{g as __pageData,c as default};
